  1→/**
  2→ * GitHub-based workflow phase detection for smart resumption.
  3→ *
  4→ * Reads phase markers from GitHub issue comments to detect workflow state
  5→ * across machines, sessions, and users. Enables skills and `sequant run`
  6→ * to resume from where they left off.
  7→ *
  8→ * Phase markers are embedded as HTML comments in issue comment bodies:
  9→ * ```
 10→ * <!-- SEQUANT_PHASE: {"phase":"exec","status":"completed","timestamp":"..."} -->
 11→ * ```
 12→ */
 13→
 14→import { GitHubProvider } from "./platforms/github.js";
 15→import {
 16→  type Phase,
 17→  type PhaseMarker,
 18→  PhaseMarkerSchema,
 19→  WORKFLOW_PHASES,
 20→} from "./state-schema.js";
 21→
 22→/** Regex to extract phase marker JSON from HTML comments */
 23→const PHASE_MARKER_REGEX = /<!-- SEQUANT_PHASE: (\{[^}]+\}) -->/g;
 24→
 25→/**
 26→ * Regex patterns for markdown code constructs that should be ignored.
 27→ * - Fenced code blocks: 3+ backticks or tildes (CommonMark spec)
 28→ * - Inline code: `...`
 29→ */
 30→const FENCED_CODE_BLOCK_REGEX = /`{3,}[\s\S]*?`{3,}|~{3,}[\s\S]*?~{3,}/g;
 31→const INLINE_CODE_REGEX = /`[^`\n]+`/g;
 32→
 33→/**
 34→ * Strip markdown code blocks and inline code from text.
 35→ * This prevents phase markers inside code examples from being parsed.
 36→ *
 37→ * @param text - The text to strip code from
 38→ * @returns Text with code blocks and inline code removed
 39→ */
 40→function stripMarkdownCode(text: string): string {
 41→  // First remove fenced code blocks (multi-line)
 42→  let result = text.replace(FENCED_CODE_BLOCK_REGEX, "");
 43→  // Then remove inline code
 44→  result = result.replace(INLINE_CODE_REGEX, "");
 45→  return result;
 46→}
 47→
 48→/**
 49→ * Format a phase marker as an HTML comment string for embedding in GitHub comments.
 50→ *
 51→ * @param marker - The phase marker data
 52→ * @returns HTML comment string like `<!-- SEQUANT_PHASE: {...} -->`
 53→ */
 54→export function formatPhaseMarker(marker: PhaseMarker): string {
 55→  return `<!-- SEQUANT_PHASE: ${JSON.stringify(marker)} -->`;
 56→}
 57→
 58→/**
 59→ * Parse all phase markers from a single comment body.
 60→ *
 61→ * Phase markers inside fenced code blocks (```...```) or inline code (`...`)
 62→ * are ignored to prevent false positives from documentation examples.
 63→ *
 64→ * @param commentBody - The full body text of a GitHub comment
 65→ * @returns Array of parsed phase markers (empty if none found)
 66→ */
 67→export function parsePhaseMarkers(commentBody: string): PhaseMarker[] {
 68→  const markers: PhaseMarker[] = [];
 69→  // Strip code blocks before matching to avoid false positives
 70→  const strippedBody = stripMarkdownCode(commentBody);
 71→  // Reset regex state for reuse
 72→  PHASE_MARKER_REGEX.lastIndex = 0;
 73→
 74→  let match: RegExpExecArray | null;
 75→  while ((match = PHASE_MARKER_REGEX.exec(strippedBody)) !== null) {
 76→    try {
 77→      const parsed = JSON.parse(match[1]);
 78→      const result = PhaseMarkerSchema.safeParse(parsed);
 79→      if (result.success) {
 80→        markers.push(result.data);
 81→      }
 82→    } catch {
 83→      // Malformed JSON — skip silently
 84→    }
 85→  }
 86→
 87→  return markers;
 88→}
 89→
 90→/**
 91→ * Detect the latest phase from an array of comment bodies.
 92→ *
 93→ * Scans all comments for phase markers and returns the most recent one
 94→ * based on the timestamp field.
 95→ *
 96→ * @param comments - Array of objects with a `body` string field
 97→ * @returns The latest phase marker, or null if no markers found
 98→ */
 99→export function detectPhaseFromComments(
100→  comments: { body: string }[],
101→): PhaseMarker | null {
102→  const allMarkers: PhaseMarker[] = [];
103→
104→  for (const comment of comments) {
105→    const markers = parsePhaseMarkers(comment.body);
106→    allMarkers.push(...markers);
107→  }
108→
109→  if (allMarkers.length === 0) {
110→    return null;
111→  }
112→
113→  // Sort by timestamp descending, return latest
114→  allMarkers.sort(
115→    (a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime(),
116→  );
117→
118→  return allMarkers[0];
