121→/**
122→ * Get all phase markers from issue comments, grouped by phase.
123→ *
124→ * Returns the latest marker for each phase that has been recorded.
125→ *
126→ * @param comments - Array of comment bodies
127→ * @returns Map of phase → latest marker for that phase
128→ */
129→export function getPhaseMap(
130→  comments: { body: string }[],
131→): Map<Phase, PhaseMarker> {
132→  const phaseMap = new Map<Phase, PhaseMarker>();
133→
134→  for (const comment of comments) {
135→    const markers = parsePhaseMarkers(comment.body);
136→    for (const marker of markers) {
137→      const existing = phaseMap.get(marker.phase);
138→      if (
139→        !existing ||
140→        new Date(marker.timestamp).getTime() >
141→          new Date(existing.timestamp).getTime()
142→      ) {
143→        phaseMap.set(marker.phase, marker);
144→      }
145→    }
146→  }
147→
148→  return phaseMap;
149→}
