153→ *
154→ * @param comments - Array of comment bodies
155→ * @returns Array of phase names that have status "completed"
156→ */
157→export function getCompletedPhasesFromComments(
158→  comments: { body: string }[],
159→): Phase[] {
160→  const phaseMap = getPhaseMap(comments);
161→  const completed: Phase[] = [];
162→
163→  for (const phase of WORKFLOW_PHASES) {
164→    const marker = phaseMap.get(phase);
165→    if (marker && marker.status === "completed") {
166→      completed.push(phase);
167→    }
168→  }
169→
170→  return completed;
171→}
