173→/**
174→ * Determine which phases to run based on completed phases and requested phases.
175→ *
176→ * Filters out phases that are already completed. If a phase failed,
177→ * it is kept in the list (for retry).
178→ *
179→ * @param requestedPhases - The phases the user wants to run
180→ * @param comments - Array of comment bodies from the issue
181→ * @returns Filtered array of phases that still need to run
182→ */
183→export function getResumablePhases(
184→  requestedPhases: readonly string[],
185→  comments: { body: string }[],
186→): string[] {
187→  const completedPhases = new Set(getCompletedPhasesFromComments(comments));
188→
189→  return requestedPhases.filter(
190→    (phase) => !completedPhases.has(phase as Phase),
191→  );
192→}
