194→/**
195→ * Check if a specific phase has been reached or passed.
196→ *
197→ * Uses WORKFLOW_PHASES ordering to determine if the target phase
198→ * is at or before the latest completed phase.
199→ *
200→ * @param targetPhase - The phase to check
201→ * @param comments - Array of comment bodies
202→ * @returns true if targetPhase has been completed or a later phase has been completed
203→ */
204→export function isPhaseCompletedOrPast(
205→  targetPhase: Phase,
206→  comments: { body: string }[],
207→): boolean {
208→  const phaseMap = getPhaseMap(comments);
209→  const targetIndex = WORKFLOW_PHASES.indexOf(targetPhase);
210→
211→  // Check if target phase itself is completed
212→  const targetMarker = phaseMap.get(targetPhase);
213→  if (targetMarker && targetMarker.status === "completed") {
214→    return true;
215→  }
216→
217→  // Check if any later phase is completed (implies target was completed)
218→  for (let i = targetIndex + 1; i < WORKFLOW_PHASES.length; i++) {
219→    const laterPhase = WORKFLOW_PHASES[i];
220→    const laterMarker = phaseMap.get(laterPhase);
221→    if (laterMarker && laterMarker.status === "completed") {
222→      return true;
223→    }
224→  }
225→
226→  return false;
227→}
