241→/**
242→ * Detect the most recent QA phase marker from issue comments.
243→ *
244→ * Extracts the commit SHA and metadata from the latest QA phase marker,
245→ * enabling incremental re-runs by identifying what changed since last QA.
246→ *
247→ * @param comments - Array of objects with a `body` string field
248→ * @returns Prior QA findings, or null if no QA phase markers found
249→ */
250→export function detectPriorQAFindings(
251→  comments: { body: string }[],
252→): PriorQAFindings | null {
253→  const allMarkers: PhaseMarker[] = [];
254→
255→  for (const comment of comments) {
256→    const markers = parsePhaseMarkers(comment.body);
257→    for (const marker of markers) {
258→      if (marker.phase === "qa") {
259→        allMarkers.push(marker);
260→      }
261→    }
262→  }
263→
264→  if (allMarkers.length === 0) {
265→    return null;
266→  }
267→
268→  // Sort by timestamp descending, return latest
269→  allMarkers.sort(
270→    (a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime(),
271→  );
272→
273→  const latest = allMarkers[0];
274→  return {
275→    commitSHA: latest.commitSHA ?? null,
276→    timestamp: latest.timestamp,
277→    status: latest.status,
278→  };
279→}
