141→export function formatDuration(seconds: number): string {
142→  if (seconds < 60) {
143→    return `${seconds.toFixed(1)}s`;
144→  }
145→  const mins = Math.floor(seconds / 60);
146→  const secs = seconds % 60;
147→  return `${mins}m ${secs.toFixed(0)}s`;
