181→async function executePhase(
182→  issueNumber: number,
183→  phase: Phase,
184→  config: ExecutionConfig,
185→  sessionId?: string,
186→  worktreePath?: string,
187→  shutdownManager?: ShutdownManager,
188→  spinner?: PhaseSpinner,
189→): Promise<PhaseResult & { sessionId?: string }> {
190→  const startTime = Date.now();
191→
192→  const prompt = await getPhasePrompt(phase, issueNumber, config.agent);
193→
194→  if (config.dryRun) {
195→    // Dry run - show the prompt that would be sent, then return
196→    if (config.verbose) {
197→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
198→      console.log(chalk.gray(`    Prompt: ${prompt}`));
199→    }
200→    return {
201→      phase,
202→      success: true,
203→      durationSeconds: 0,
204→      output: prompt,
205→    };
206→  }
207→
208→  if (config.verbose) {
209→    console.log(chalk.gray(`    Prompt: ${prompt}`));
210→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
211→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
212→    }
213→  }
214→
215→  // Determine working directory and environment
216→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
217→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
218→
219→  // Resolve file context for file-oriented drivers (e.g., Aider --file)
220→  let files: string[] | undefined;
221→  if (config.agent && config.agent !== "claude-code") {
222→    try {
223→      const output = execSync("git diff --name-only main...HEAD", {
224→        cwd,
225→        encoding: "utf-8",
226→        stdio: ["pipe", "pipe", "pipe"],
227→      }).trim();
228→      if (output) {
229→        files = output.split("\n").filter(Boolean);
230→      }
231→    } catch {
232→      // No changed files or git error — proceed without file context
233→    }
234→  }
235→
236→  // Check if shutdown is in progress
237→  if (shutdownManager?.shuttingDown) {
238→    return {
239→      phase,
240→      success: false,
241→      durationSeconds: 0,
242→      error: "Shutdown in progress",
243→    };
244→  }
245→
246→  // Create abort controller for timeout
247→  const abortController = new AbortController();
248→  const timeoutId = setTimeout(() => {
249→    abortController.abort();
250→  }, config.phaseTimeout * 1000);
251→
252→  // Register abort controller with shutdown manager for graceful shutdown
253→  // Uses add/remove to support concurrent phase execution (#404)
254→  if (shutdownManager) {
255→    shutdownManager.addAbortController(abortController);
256→  }
257→
258→  // Build environment with worktree isolation variables
259→  const env: Record<string, string> = {
260→    ...process.env,
261→    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
262→  };
263→
264→  // Set worktree isolation environment variables
265→  if (shouldUseWorktree) {
266→    env.SEQUANT_WORKTREE = worktreePath;
267→    env.SEQUANT_ISSUE = String(issueNumber);
268→  }
269→
270→  // Set orchestration context for skills to detect they're part of a workflow
271→  // Skills can check these to skip redundant pre-flight checks
272→  env.SEQUANT_ORCHESTRATOR = "sequant-run";
273→  env.SEQUANT_PHASE = phase;
274→
275→  // Propagate issue type for skills to adapt behavior (e.g., lighter QA for docs)
276→  if (config.issueType) {
277→    env.SEQUANT_ISSUE_TYPE = config.issueType;
278→  }
279→
280→  // Track whether we're actively streaming verbose output
281→  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
282→  // (Issue #283: ora's stop() clears the current line, which can truncate output when
283→  // pause/resume is called for every chunk in rapid succession)
284→  let verboseStreamingActive = false;
285→
286→  // Safety: never resume a session when worktree isolation is active.
287→  // Even if THIS phase doesn't use the worktree, a previous phase may have
288→  // created the session there. Resuming from a different cwd crashes the SDK
289→  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
290→  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
291→  const canResume = sessionId && !worktreePath;
