153→export async function getIssueInfo(
154→  issueNumber: number,
155→): Promise<{ title: string; labels: string[] }> {
156→  try {
157→    const result = spawnSync(
158→      "gh",
159→      ["issue", "view", String(issueNumber), "--json", "title,labels"],
160→      { stdio: "pipe" },
161→    );
162→
163→    if (result.status === 0) {
164→      const data = JSON.parse(result.stdout.toString());
165→      return {
166→        title: data.title || `Issue #${issueNumber}`,
167→        labels: Array.isArray(data.labels)
168→          ? data.labels.map((l: { name: string }) => l.name)
169→          : [],
170→      };
171→    }
172→  } catch {
173→    // Ignore errors, use defaults
174→  }
175→
176→  return { title: `Issue #${issueNumber}`, labels: [] };
177→}
